sql:
SELECT AVG(number_of_findings) AS average_issues
FROM code_review_metrics
WHERE review_status = 'rejected';

SELECT MIN(review_duration) 
FROM code_reviews 
WHERE review_status = 'rejected';

SELECT MAX(commit_count) AS max_total_commits
FROM (
    SELECT c.repository_id, COUNT(c.commit_id) AS commit_count
    FROM commits c
    GROUP BY c.repository_id
) AS commit_counts;

external_knowledge:
- 'Significant contributions' are measured by the total commit size of the developer;
- 'Strong network influence' is indicated by an average betweenness centrality greater than 0.5;
- 'Notable number of repositories' means the project has more than 2 repositories;
- 'Matching total commit size' refers to the total commit size of the developer being equal to the total commits of the project.

- "Seeds they've planted" refers to the total number of commits made by the developers;
- "Flowers they've tended" refers to the total number of code reviews performed by the developers;
- The "garden" is a metaphor for the development environment;
- The "most prolific gardener" is the developer with the highest total contributions.

- 'software engineer' refers to the role of the developer in the database;
- 'approved' refers to the status of the code review;
- 'typical approved review time' refers to the average review duration of all approved code reviews.

- 'shine the brightest' refers to the top 5 developers based on their total activity;
- 'tended the most flowers' refers to the number of repository changes;
- 'nurtured the most seeds' refers to the number of code reviews.

sql:
SELECT developer_id, resolution_time
FROM resolution_times
WHERE resolution_time > (SELECT AVG(resolution_time) FROM resolution_times);

external_knowledge:
